document.addEventListener("DOMContentLoaded",function(){const t="../components/";fetch(t+"header.html").then(t=>t.text()).then(t=>{const e=document.getElementById("header-container");var n;e&&(e.innerHTML=t,n=e,function(t){const e=t.split("/").filter(t=>t&&!t.includes(".html")).length;e>0&&"../".repeat(e)}(window.location.pathname),n.querySelectorAll("a[href], link[href], script[src]").forEach(t=>{const e="SCRIPT"===t.tagName?"src":"href",n=t.getAttribute(e);!n||n.startsWith("http")||n.startsWith("//")||n.startsWith("#")||n.endsWith(".html")||n.endsWith(".css")||n.endsWith(".js")}))}).catch(t=>console.error("Failed to load header:",t)),fetch(t+"footer.html").then(t=>t.text()).then(t=>{const e=document.getElementById("footer-container");e&&(e.innerHTML=t)}).catch(t=>console.error("Failed to load footer:",t))});